function workspaceCandidatePayload(primaryDetail, secondaryDetails, values) {
    const sources = [primaryDetail, ...(Array.isArray(secondaryDetails) ? secondaryDetails : [])];
    if (sources.length === 0 || sources.length > 10) return null;
    const sourceSessions = [];
    const evidenceRefs = [];
    for (const detail of sources) {
        const sessionId = detail?.session?.session_id;
        const evidence = Array.isArray(detail?.evidence_refs) ? detail.evidence_refs[0] : null;
        if (typeof sessionId !== "string" || !sessionId || !evidence?.kind || !evidence?.reference_id || sourceSessions.includes(sessionId)) return null;
        sourceSessions.push(sessionId);
        evidenceRefs.push({ kind: evidence.kind, reference_id: evidence.reference_id });
    }
    return { status: "candidate", ...values, source_sessions: sourceSessions, evidence_refs: evidenceRefs };
}

function workspaceProposalReference(reference, detail) {
    const events = Array.isArray(detail?.events) ? detail.events : [];
    const runs = Array.isArray(detail?.runs) ? detail.runs : [];
    if (reference?.kind === "event") return { kind: "event", value: events.find(item => item.event_id === reference.reference_id) ?? null };
    if (reference?.kind === "run") return { kind: "run", value: runs.find(item => item.run_id === reference.reference_id) ?? null };
    if (reference?.kind === "trace") return { kind: "trace", value: runs.find(item => item.trace_id === reference.reference_id) ?? null };
    if (reference?.kind === "gate" && reference.reference_id === "terminal") return { kind: "event", value: events.find(item => ["session.shutdown", "session.task_complete", "SessionEnd", "Stop"].includes(item.type)) ?? null };
    if (reference?.kind === "gate" && reference.reference_id === "error") return { kind: "event", value: events.find(item => item.status === "error") ?? null };
    return { kind: null, value: null };
}

function workspaceApplyDraftPayload(proposalId, rootId, files) {
    if (typeof proposalId !== "string" || !proposalId || typeof rootId !== "string" || !rootId || !Array.isArray(files) || files.length < 1 || files.length > 10) return null;
    if (files.some(file => typeof file?.relative_path !== "string" || !file.relative_path || typeof file?.replacement_text !== "string")) return null;
    return { proposal_id: proposalId, root_id: rootId, files };
}

function workspaceApplySelectionPayload(selectionRevision, selectedHunkIds) {
    if (!Number.isSafeInteger(selectionRevision) || selectionRevision < 0 || !Array.isArray(selectedHunkIds) || selectedHunkIds.length < 1 || selectedHunkIds.some(id => typeof id !== "string" || !id)) return null;
    return { selection_revision: selectionRevision, selected_hunk_ids: selectedHunkIds };
}

function workspaceApplyApprovalPayload(selectionRevision, approvalDigest) {
    if (!Number.isSafeInteger(selectionRevision) || selectionRevision < 0 || typeof approvalDigest !== "string" || !approvalDigest) return null;
    return { selection_revision: selectionRevision, approval_digest: approvalDigest };
}

function workspaceApplyRequest() { return undefined; }

function workspaceApplyView(value) {
    const state = typeof value?.state === "string" ? value.state : "unavailable";
    const root = value?.root && typeof value.root.kind === "string" && typeof value.root.label === "string"
        ? { kind: value.root.kind, label: value.root.label }
        : null;
    return {
        state,
        selection_revision: Number.isSafeInteger(value?.selection_revision) ? value.selection_revision : null,
        approval_digest: typeof value?.approval_digest === "string" ? value.approval_digest : null,
        root,
        canApply: state === "approved",
        canRollback: state === "applied" && typeof value?.apply_id === "string" && !!value.apply_id,
    };
}

function workspaceApplyDraftReview(draft) {
    const files = Array.isArray(draft?.files) ? draft.files : [];
    const hunks = Array.isArray(draft?.hunks) ? draft.hunks : [];
    return files.map(file => ({ ...file, hunks: hunks.filter(hunk => hunk?.relative_path === file?.relative_path) }));
}

function workspaceApplyConfirmation(state) {
    return {
        selection_revision: Number.isSafeInteger(state?.selection_revision) ? state.selection_revision : null,
        approval_digest: typeof state?.approval_digest === "string" ? state.approval_digest : null,
        file_count: Array.isArray(state?.files) ? state.files.length : 0,
    };
}

export { workspaceCandidatePayload, workspaceProposalReference, workspaceApplyDraftPayload, workspaceApplySelectionPayload, workspaceApplyApprovalPayload, workspaceApplyRequest, workspaceApplyView, workspaceApplyDraftReview, workspaceApplyConfirmation };
